INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1564f4c0-2021-4720-a305-067b22743508',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAPI vs tRPC — Skip Schema Gen, Get End-to-End Type Safety$escape$,
  $escape$tRPC eliminates the contract-generation step that OpenAPI workflows depend on. Instead of defining a spec, running `openapi-typescript` or `openapi-generator`, and consuming generated types, tRPC shares TypeScript types directly from router to client — zero codegen, zero drift.

Procedure types map cleanly to REST semantics: `query` for reads, `mutation` for writes, and `subscription` for WebSocket streams. Each procedure is validated with Zod at runtime, giving you the same schema-enforcement guarantees as an OpenAPI request validator middleware — but colocated with your handler logic, not in a separate spec file.

React Query integration is first-class. `trpc.user.getById.useQuery()` returns the same `{ data, isLoading, error }` shape as vanilla React Query, but input and output types are inferred from your server-side Zod schema — no `components/schemas` wrangling, no stale generated files to commit.

The tradeoff is real: tRPC only works in TypeScript-only stacks. If you need a public API consumed by third-party or non-TS clients, OpenAPI remains the correct choice. For internal full-stack TypeScript monorepos, tRPC eliminates an entire class of type-drift bugs that openapi-typescript codegen introduces between spec updates.$escape$,
  $escape$// server: router.ts
const appRouter = router({
  user: router({
    getById: publicProcedure
      .input(z.object({ id: z.string() }))
      .query(async ({ input, ctx }) => {
        return ctx.db.user.findUnique({ where: { id: input.id } });
      }),
    create: publicProcedure
      .input(z.object({ name: z.string(), email: z.string().email() }))
      .mutation(async ({ input, ctx }) => {
        return ctx.db.user.create({ data: input });
      }),
  }),
});
export type AppRouter = typeof appRouter;

// client: UserProfile.tsx
const { data, isLoading } = trpc.user.getById.useQuery({ id: userId });$escape$,
  $escape$typescript$escape$,
