INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3b195450-7d6d-45be-b035-50e9b925a89d',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAPI Pagination — Modeling Cursor vs Offset and Infinite Scroll Contracts$escape$,
  $escape$OpenAPI doesn't enforce pagination, but your schema contract dictates how clients consume it. For offset-based pagination, expose `limit` and `offset` as query parameters with explicit `minimum`/`maximum` constraints, and include a `total` field in the response envelope — but recognize that `total` is expensive on large datasets and often stale by the time the client reads it. Cursor-based pagination is superior for infinite scroll: use an opaque `cursor` string (base64-encoded timestamp + ID composite), return `next_cursor` and `has_more` in your envelope, and never expose the cursor's internal structure in your schema description. Mark `total` as `nullable: true` and document in the field's `description` that it's omitted for cursor-based responses. Use `oneOf` on the response schema to formally differentiate the two pagination modes if your API supports both. For infinite scroll clients, the contract that matters is `has_more: boolean` — make it required, not optional. Document `deprecated: true` on `total` when migrating from offset to cursor. Link your `Link` header RFC 5988 behavior via `externalDocs`.$escape$,
  $escape$components:
  schemas:
    CursorPage:
      type: object
      required: [data, has_more]
      properties:
        data:
          type: array
          items:
            $ref: '#/components/schemas/Item'
        next_cursor:
          type: string
          nullable: true
          description: Opaque cursor; pass as `cursor` on next request.
        has_more:
          type: boolean
        total:
          type: integer
          nullable: true
          deprecated: true
          description: Omitted for cursor-paginated responses.$escape$,
  $escape$bash$escape$,
