INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'db7e66bd-0416-4d13-899f-9b7529e0ce6e',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAPI — Documenting HTTP Caching: ETags, Cache-Control, and 304 Responses$escape$,
  $escape$OpenAPI specs routinely omit caching semantics, leaving clients and CDNs to guess. Model them explicitly. For GET endpoints that support conditional requests, declare `If-None-Match` and `If-Modified-Since` as header parameters — this signals to generated clients and gateways that these inputs are intentional. Document `ETag` and `Cache-Control` in the `headers` object of your `200` response. The `ETag` value should reflect the weak/strong validator syntax (`"abc123"` or `W/"abc123"`). Always include a `304 Not Modified` response with no `content` key — OpenAPI 3.x treats its absence as an intentional empty body, which matches the HTTP spec exactly. For CDN-aware APIs, also document `Vary: Accept-Encoding, Accept` so shared caches know which dimensions produce distinct responses. Apply `Cache-Control: max-age=3600, must-revalidate` on mutable resources and `immutable` on versioned or content-addressed assets. Tooling like Redoc and SwaggerUI will surface these headers in generated docs, making caching contracts first-class API guarantees rather than implicit implementation details.$escape$,
  $escape$paths:
  /articles/{id}:
    get:
      parameters:
        - name: If-None-Match
          in: header
          schema: { type: string }
        - name: If-Modified-Since
          in: header
          schema: { type: string, format: date-time }
      responses:
        '200':
          headers:
            ETag:
              schema: { type: string, example: '"d4f9a1"' }
            Cache-Control:
              schema: { type: string, example: 'max-age=3600, must-revalidate' }
            Vary:
              schema: { type: string, example: 'Accept-Encoding, Accept' }
          content:
            application/json:
              schema: { $ref: '#/components/schemas/Article' }
        '304':
          description: Not Modified — client cache is still valid$escape$,
