INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ea6077e1-ccd8-4781-b402-308b3abde868',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAPI Contract Testing — Lock Your API Behavior with Schemathesis and Prism$escape$,
  $escape$Contract testing in OpenAPI means treating your `openapi.yaml` as the source of truth and verifying that both your server and consumers honor it. Two tools own this space: **Schemathesis** for server-side property-based contract testing, and **Stoplight Prism** for mock-driven consumer testing.

Schemathesis reads your OpenAPI 3.x document and auto-generates hundreds of HTTP test cases using property-based fuzzing — it tests every path, validates response schemas against `components/schemas`, checks status codes, and flags undocumented responses. Run it in CI with `schemathesis run openapi.yaml --checks all --base-url http://localhost:5000`.

Prism spins up a mock server from your spec: `prism mock openapi.yaml`. Consumers write integration tests against this mock, guaranteeing they only call documented endpoints with valid request shapes. If the spec changes and breaks consumer tests, the contract is violated — caught before deployment.

The critical discipline: keep your spec as the *first* artifact, not a post-hoc annotation. Use `x-internal: true` to exclude private endpoints from contract surface. Pair Schemathesis with `--validate-schema=true` to catch spec authoring errors before they propagate.$escape$,
  $escape$# CI contract test pipeline
# 1. Validate the spec itself
npx @redocly/cli lint openapi.yaml

# 2. Start your real server
dotnet run &

# 3. Run Schemathesis against live server
schemathesis run openapi.yaml \
  --base-url http://localhost:5000 \
  --checks all \
  --validate-schema=true \
  --hypothesis-max-examples=50

# 4. Spin up Prism mock for consumer tests
npx @stoplight/prism-cli mock openapi.yaml --port 4010 &
npm run test:integration  # tests hit :4010, not real server$escape$,
  $escape$bash$escape$,
