INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0f270502-cbe4-4b81-95ab-54a3d48c89a7',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAPI Security — Locking Down Input Validation, CSRF, and Injection at the Spec Layer$escape$,
  $escape$OpenAPI schemas are your first line of defense, but they only enforce what you wire up server-side. Use `pattern`, `minLength`, `maxLength`, and `enum` on every user-supplied string field — these constraints feed directly into validators like `express-openapi-validator` or `oapi-codegen` and block injection payloads before they hit business logic. For `format: uri` fields, add an explicit `pattern` to allowlist schemes (`^https://`) — otherwise you've opened an SSRF vector. Cookie-based `securitySchemes` (`in: cookie`) require `SameSite=Strict` and a CSRF double-submit token; OpenAPI lets you declare both a cookie scheme and a header scheme in tandem — enforce both in your middleware. Treat your `/openapi.json` endpoint like GraphQL introspection: gate it behind auth in production. Leaking full schema exposes every parameter name, format, and internal path to attackers. Use `x-internal: true` on sensitive operations and strip them at doc-generation time. Run `redocly lint` with `security-defined` rule enabled — it fails the build if any operation lacks a `security` declaration.$escape$,
  $escape$# openapi.yaml — injection-hardened request body
requestBody:
  required: true
  content:
    application/json:
      schema:
        type: object
        required: [username, redirectUrl]
        properties:
          username:
            type: string
            minLength: 3
            maxLength: 32
            pattern: '^[a-zA-Z0-9_-]+$'   # blocks SQLi / XSS chars
          redirectUrl:
            type: string
            format: uri
            pattern: '^https://app\.example\.com/'  # prevents open redirect + SSRF$escape$,
  $escape$bash$escape$,
